const items = $input.all();
return items.map(item => {
  const d = item.json;
  return { json: {
    name: d.title || d.name || d.hostName || d.businessName || '',
    company: d.title || d.businessName || d.name || '',
    email: d.email || d.contactEmail || '',
    phone: d.phone || d.contactPhone || d.phoneNumber || '',
    website: d.website || d.url || d.websiteUrl || '',
    address: d.address || d.fullAddress || d.location || '',
    source: d.searchPageUrl ? 'google_maps' : d.hostName ? 'airbnb' : 'yelp',
    rating: d.totalScore || d.rating || d.stars || null,
    reviewCount: d.reviewsCount || d.numberOfReviews || 0,
    category: d.categoryName || d.category || 'property management',
    scrapedAt: new Date().toISOString()
  }};
});

const items = $input.all();
return items.filter(item => {
  try {
    const text = item.json.output || item.json.text || JSON.stringify(item.json);
    const match = text.match(/\{[\s\S]*\}/);
    if (!match) return true;
    const result = JSON.parse(match[0]);
    return result.valid !== false && (result.confidence || 0.5) >= 0.5;
  } catch(e) { return true; }
});

const items = $input.all();
const seen = new Set();
const unique = [];
for (const item of items) {
  const key = (item.json.email || item.json.phone || item.json.company || JSON.stringify(item.json)).toLowerCase().trim();
  if (!seen.has(key)) { seen.add(key); unique.push(item); }
}
return unique;

const data = JSON.parse(query);
const weights = {fit:0.25, size:0.15, pain:0.20, timing:0.15, budget:0.10, access:0.15};
let score = 0;
for (const [k,w] of Object.entries(weights)) { score += (data[k]||5) * w; }
score = Math.round(score * 10) / 10;
return JSON.stringify({score, tier: score>=7?'A':score>=5?'B':'C', weights, breakdown: data});

const items = $input.all();
return items.map(item => {
  const s = item.json.score || 5;
  const boost = item.json.replied ? 3 : item.json.opened ? 1.5 : 0;
  const newScore = Math.min(10, s + boost);
  return { json: { ...item.json, score: newScore, tier: newScore>=7?'A':newScore>=5?'B':'C', rescored: true } };
});

const err = $input.first().json;
return [{ json: {
  workflow: err.workflow?.name || 'Pipeline v3.0',
  node: err.execution?.error?.node?.name || 'Unknown',
  message: err.execution?.error?.message || 'No message',
  severity: (err.execution?.error?.message||'').match(/timeout|ECONNRESET|429|503/) ? 'warning' : 'critical',
  retryable: ['ECONNRESET','ETIMEDOUT','429','503'].some(e => (err.execution?.error?.message||'').includes(e)),
  ts: new Date().toISOString()
}}];

const items = $input.all();
return items.map(item => {
  let ai;
  try {
    const text = item.json.output || item.json.text || JSON.stringify(item.json);
    const match = text.match(/\{[\s\S]*\}/);
    ai = match ? JSON.parse(match[0]) : {score:5, tier:'B', urgency:'warm'};
  } catch(e) { ai = {score:5, tier:'B', urgency:'warm', parseError: e.message}; }
  return { json: { ...item.json, ai, tier: ai.tier||'B', score: ai.score||5 } };
});

const items = $input.all();
return items.map(item => {
  const content = (item.json.data?.markdown || '').substring(0, 2000);
  const pricing = content.match(/\$\d+[\d,]*/g) || [];
  const features = ['automation','integration','API','dashboard','reporting','analytics','scheduling']
    .filter(f => content.toLowerCase().includes(f));
  return { json: { ...item.json, competitorAnalysis: {
    competitor: item.json.ai?.competitorLikely || 'unknown',
    pricingMentions: pricing.slice(0,5),
    featuresFound: features,
    weaknesses: features.length < 3 ? 'Limited feature set — room for displacement' : 'Feature-rich — focus on service/price differentiation'
  }}};
});

const items = $input.all();
return items.map(item => {
  const ai = item.json.ai || {};
  const comp = item.json.competitorAnalysis || {};
  const hook = ai.personalizationHook || 'your property management business';
  const pain = (ai.painPoints || ['automation'])[0];
  const objection = ai.objectionPrediction || '';

  return { json: { ...item.json,
    messages: {
      emailSubject: 'Quick question about ' + hook.substring(0, 60),
      emailBody: (ai.emailColdOpen || 'Hi,') + '\n\n' +
        'I noticed ' + hook + ' and thought Otter Labs could help with ' + pain + '.\n\n' +
        (comp.weaknesses ? 'I know tools like ' + (comp.competitor||'your current setup') + ' can be limiting — ' : '') +
        'we\'ve been helping similar property managers save 15+ hours/week on operations.\n\n' +
        'Would you be open to a quick 15-min chat?\n\n' +
        'Book here: https://cal.com/YOUR_USERNAME/demo\n\nBest,\nJordan @ Otter Labs',
      smsMessage: (ai.smsColdOpen || 'Hey!') + ' ' +
        'Quick Q about ' + (item.json.lead?.company || 'your business') + ' — ' +
        'we help PMs automate ops & save 15+ hrs/week. Worth a 15min chat? ' +
        'cal.com/YOUR_USERNAME/demo',
      channel: ai.recommendedChannel || 'multi-channel'
    }
  }};
});

const items = $input.all();
return items.map(item => {
  const addr = (item.json.lead?.address || item.json.address || '').toLowerCase();
  let tz = 'America/New_York';
  if (addr.match(/\b(ca|wa|or|nv|az)\b|los angeles|san francisco|seattle|phoenix|denver/)) tz = 'America/Los_Angeles';
  else if (addr.match(/\b(tx|il|mn|wi|mo|co)\b|chicago|dallas|austin|denver|nashville/)) tz = 'America/Chicago';
  else if (addr.match(/\b(co|mt|ut|nm)\b/)) tz = 'America/Denver';

  const offsets = {'America/New_York':-5,'America/Chicago':-6,'America/Denver':-7,'America/Los_Angeles':-8};
  const offset = offsets[tz] || -5;
  const optimalHourUTC = 10 - offset; // 10am local
  const now = new Date();
  let waitHrs = optimalHourUTC - now.getUTCHours();
  if (waitHrs <= 0) waitHrs += 24;
  const sendDate = new Date(now.getTime() + waitHrs * 3600000);
  const day = sendDate.getUTCDay();
  if (day === 0) waitHrs += 24;
  if (day === 6) waitHrs += 48;

  return { json: { ...item.json, timing: { tz, optimalHourUTC, waitHours: Math.max(0.5, waitHrs), sendAt: new Date(now.getTime() + waitHrs*3600000).toISOString() } } };
});

const items = $input.all();
const m = {
  total: items.length,
  enrichRate: Math.round(items.filter(i => i.json.lead?.email).length / Math.max(items.length,1) * 100),
  tiers: {A:0, B:0, C:0},
  avgScore: 0,
  channels: {},
  ts: new Date().toISOString()
};
let sum = 0;
items.forEach(i => {
  m.tiers[i.json.tier||'C']++;
  sum += i.json.score||0;
  const ch = i.json.ai?.recommendedChannel||'unknown';
  m.channels[ch] = (m.channels[ch]||0)+1;
});
m.avgScore = Math.round(sum/Math.max(items.length,1)*10)/10;
return [{json: m}];

