const items = $input.all();
return items.map(item => {
  const lead = item.json.lead || item.json;
  const timing = item.json.timing || {};
  const ai = item.json.ai || {};

  // Determine industry/vertical
  const company = (lead.company || '').toLowerCase();
  const category = (lead.category || '').toLowerCase();
  const siteContent = (lead.siteContent || '').toLowerCase();

  let industry = 'general';
  if (category.includes('property') || company.includes('property') || siteContent.includes('property management')) {
    industry = 'property-management';
  } else if (category.includes('vacation') || siteContent.includes('short-term') || siteContent.includes('airbnb') || siteContent.includes('str')) {
    industry = 'str-hosting';
  } else if (category.includes('laundro') || company.includes('laundro') || siteContent.includes('laundromat')) {
    industry = 'laundromat';
  } else if (category.includes('clean') || siteContent.includes('cleaning service')) {
    industry = 'cleaning';
  }

  // Determine send window based on timezone
  const tz = timing.tz || 'America/New_York';
  let sendWindow = 'morning'; // default 9-11am
  const hour = timing.optimalHourUTC || 15;
  if (hour >= 12 && hour < 17) sendWindow = 'afternoon';
  if (hour >= 17) sendWindow = 'evening';

  // Build campaign name: {industry}_{sendWindow}_{date}
  const today = new Date();
  const weekNum = Math.ceil((today.getDate()) / 7);
  const monthNames = ['jan','feb','mar','apr','may','jun','jul','aug','sep','oct','nov','dec'];
  const campaignName = `${industry}_${sendWindow}_${monthNames[today.getMonth()]}${today.getFullYear()}_w${weekNum}`;

  // Map to Instantly campaign config
  const campaignConfigs = {
    'property-management': {
      subject_lines: [
        'Quick question about {{first_name}}\'s property ops',
        '{{company_name}} — saving 15+ hrs/week on management',
        'Automating the busywork at {{company_name}}'
      ],
      from_name: 'Jordan @ Otter Labs',
      daily_limit: 30,
      wait_days_between: 3
    },
    'str-hosting': {
      subject_lines: [
        'Your STR listings — quick thought',
        '{{first_name}}, automating guest comms at scale',
        'Saw {{company_name}} on Airbnb — quick question'
      ],
      from_name: 'Jordan @ Otter Labs',
      daily_limit: 25,
      wait_days_between: 4
    },
    'laundromat': {
      subject_lines: [
        'Quick question about {{company_name}}',
        '{{first_name}} — modernizing laundromat ops',
        'Saw {{company_name}} — thought of something'
      ],
      from_name: 'Jordan @ Otter Labs',
      daily_limit: 20,
      wait_days_between: 5
    },
    'general': {
      subject_lines: [
        'Quick question for {{first_name}}',
        '{{company_name}} — thought you\'d want to see this',
        'Saving time at {{company_name}}'
      ],
      from_name: 'Jordan @ Otter Labs',
      daily_limit: 25,
      wait_days_between: 3
    }
  };

  const config = campaignConfigs[industry] || campaignConfigs['general'];

  // Pick send time schedule based on window
  const schedules = {
    'morning': { start_hour: '09:00', end_hour: '11:00' },
    'afternoon': { start_hour: '13:00', end_hour: '15:00' },
    'evening': { start_hour: '16:00', end_hour: '18:00' }
  };

  return { json: {
    ...item.json,
    campaign: {
      name: campaignName,
      industry: industry,
      sendWindow: sendWindow,
      timezone: tz,
      schedule: schedules[sendWindow] || schedules['morning'],
      config: config,
      // Custom variables for this lead
      customVars: {
        first_name: (lead.name || '').split(' ')[0] || '',
        last_name: (lead.name || '').split(' ').slice(1).join(' ') || '',
        company_name: lead.company || '',
        email: lead.email || '',
        personalization_hook: ai.personalizationHook || '',
        pain_point: (ai.painPoints || ['automation'])[0] || '',
        cold_open: ai.emailColdOpen || '',
        email_subject: item.json.outreach?.email?.subject || item.json.messages?.emailSubject || config.subject_lines[0],
        email_body: item.json.outreach?.email?.body || item.json.messages?.emailBody || '',
        booking_link: 'https://cal.com/YOUR_USERNAME/demo',
        tier: item.json.tier || 'A',
        score: String(item.json.score || 0)
      }
    }
  }};
});

const items = $input.all();
return items.map(item => {
  // Try to get campaign ID from various response formats
  const d = item.json;
  let campaignId = d.id || d.campaign_id || 
    (d.data && d.data[0]?.id) || 
    (d.campaigns && d.campaigns[0]?.id) ||
    (Array.isArray(d) && d[0]?.id) || '';

  return { json: { ...item.json, campaignId } };
});
